import{listUsuarios,saveUsuario,deleteUsuario,listSetores,saveSetor,deleteSetor,listMaquinas,saveMaquina,deleteMaquina,listTurnos,saveTurno,deleteTurno,listAudit,listDiarios,saveDiario,syncPending}from'./services/api';
