function Login({onOk}:{onOk:()=>void}){const[u,setU]=useState('ana.peliteiro'),[s,setS]=useState('admin123'),[err,setErr]=useState('');async function go(e:any){e.preventDefault();setErr('');try{await login(u,s);onOk()}catch(x:any){setErr(x.message||'Usuário, senha ou status inválido.')}}return <div className="login"><div className="loginPanel"><div className="brand"><div className="logo">DB</div><h1>Diário de Bordo Trevo</h1><p>Operação conectada e rastreável.</p></div><form className="card loginCard" onSubmit={go}><label>Usuário<input value={u} onChange={e=>setU(e.target.value)} placeholder="ana.peliteiro" autoCapitalize="none" autoCorrect="off"/></label><label>Senha<input type="password" value={s} onChange={e=>setS(e.target.value)}/></label>{err&&<div className="err">{err}</div>}<button className="primary">Entrar</button></form></div></div>}
function Shell(){const[tab,setTab]=useState('home'),[online,setOnline]=useState(navigator.onLine),[tick,setTick]=useState(0),[profileOpen,setProfileOpen]=useState(false),[dark,setDark]=useState(localStorage.getItem('dbt_theme')==='dark');useEffect(()=>{document.body.classList.toggle('darkTheme',dark);localStorage.setItem('dbt_theme',dark?'dark':'light')},[dark]);useEffect(()=>{const a=()=>setOnline(true),b=()=>setOnline(false);addEventListener('online',a);addEventListener('offline',b);return()=>{removeEventListener('online',a);removeEventListener('offline',b)}},[]);async function sync(){await syncPending();setTick(tick+1)}const me=currentUser()!;return <><header className="topbar"><button className="logoButton" onClick={()=>setProfileOpen(true)} aria-label="Abrir menu do perfil"><div className="miniLogo">DB</div></button><div className="appIdentity"><div><b>Diário de Bordo Trevo</b><span>{me.nome} • {me.perfil}</span></div></div><div className={online?'pill ok':'pill bad'}>{online?<Wifi size={14}/>:<WifiOff size={14}/>} {online?'Online':'Offline'}</div></header><main>{tab==='home'&&<HomePage tick={tick}/>} {tab==='novo'&&<NovoDiario onSaved={()=>setTab('historico')}/>} {tab==='historico'&&<Historico/>} {tab==='admin'&&<Admin/>}</main><nav className="bottomNav"><button onClick={()=>setTab('home')} className={tab==='home'?'active':''}><Home/>Hoje</button><button onClick={()=>setTab('novo')} className={tab==='novo'?'active':''}><Plus/>Novo</button><button onClick={()=>setTab('historico')} className={tab==='historico'?'active':''}><History/>Histórico</button>{isAdmin()&&<button onClick={()=>setTab('admin')} className={tab==='admin'?'active':''}><Users/>Admin</button>}</nav><ProfileDrawer open={profileOpen} onClose={()=>setProfileOpen(false)} onSync={sync} dark={dark} setDark={setDark}/></>}
function ProfileDrawer({open,onClose,onSync,dark,setDark}:{open:boolean;onClose:()=>void;onSync:()=>void;dark:boolean;setDark:(v:boolean)=>void}){const me=currentUser()!;const[showProfile,setShowProfile]=useState(false),[showPassword,setShowPassword]=useState(false),[senha,setSenha]=useState(''),[senha2,setSenha2]=useState(''),[msg,setMsg]=useState('');if(!open)return null;async function trocarSenha(){if(senha.length<6)return setMsg('A senha precisa ter no mínimo 6 caracteres.');if(senha!==senha2)return setMsg('As senhas não conferem.');await saveUsuario({id:me.id,senha,trocar_senha:false});setSenha('');setSenha2('');setMsg('Senha alterada com sucesso.')}return <div className="drawerBackdrop" onClick={onClose}><aside className="profileDrawer" onClick={e=>e.stopPropagation()}><div className="drawerHeader"><div className="drawerLogo">DB</div><button className="iconBtn" onClick={onClose}><X size={20}/></button></div><h2>{me.nome}</h2><p>{me.usuario} • {me.perfil}</p><div className="drawerMeta"><span>{me.setor}</span><span>{me.cargo}</span></div><div className="drawerActions"><button className="drawerAction" onClick={()=>setShowProfile(!showProfile)}><UserRound size={18}/> Meu Perfil</button><button className="drawerAction" onClick={()=>setShowPassword(!showPassword)}><KeyRound size={18}/> Alterar Senha</button><button className="drawerAction" onClick={onSync}><RefreshCcw size={18}/> Sincronizar agora</button><button className="drawerAction" onClick={()=>setDark(!dark)}>{dark?<Sun size={18}/>:<Moon size={18}/>} {dark?'Tema claro':'Tema escuro'}</button><button className="drawerAction dangerLine" onClick={()=>{logout();location.reload()}}><LogOut size={18}/> Sair</button></div>{showProfile&&<div className="drawerPanel"><b>Meu Perfil</b><p><strong>Nome:</strong> {me.nome}</p><p><strong>Usuário:</strong> {me.usuario}</p><p><strong>Setor:</strong> {me.setor}</p><p><strong>Cargo:</strong> {me.cargo}</p><p><strong>Perfil:</strong> {me.perfil}</p></div>}{showPassword&&<div className="drawerPanel"><b>Alterar Senha</b><label>Nova senha<input type="password" value={senha} onChange={e=>setSenha(e.target.value)} placeholder="mínimo 6 caracteres"/></label><label>Confirmar senha<input type="password" value={senha2} onChange={e=>setSenha2(e.target.value)} /></label>{msg&&<div className="hint">{msg}</div>}<button className="primary" onClick={trocarSenha}><Save size={18}/> Salvar nova senha</button></div>}</aside></div>}

type AreaEnvase='Envase 1'|'Envase 2';
type ViewMode='maquina'|'turno';
type CritFilter='todos'|'desvios'|'atencoes';
type PcpStatus='sim'|'nao';
type MachineEntry={
  maquina:string; pcpStatus:PcpStatus; motivo?:string; ocorrido?:string; skuAtual:string; skuProgramado?:string; programado:string; produzido:string; proximosSkus?:string; novaSequencia?:string;
  ultimoCip:string; proximoCip:string; fezCip:'sim'|'nao'; parada4h:'sim'|'nao'; paradaInicio?:string; paradaFim?:string; paradaMotivo?:string; cipRenovacao?:'sim'|'nao'; cipMotivo?:string;
  pessoas?:string; observacoes:string;
};
type PassagemV6={version:'v6-envase';area:AreaEnvase;turno:string;data:string;lider:string;liderId:string;criadoEm:string;maquinas:MachineEntry[];observacoesGerais:string};
type OperationalItem={record:Diario;payload:PassagemV6;machine:MachineEntry;status:'conforme'|'atencao'|'desvio';reason:string;turno:string;area:AreaEnvase;machineName:string;criadoEm:string;lider:string};
const V6_PREFIX='V6_ENVASE_JSON:';
const DEFAULT_MACHINES:Record<AreaEnvase,string[]>={
  'Envase 1':['Braskop 1','Braskop 2','Braskop 3','Dmax 6','Serac 1','Serac 2'],
  'Envase 2':['Dmax 1','Dmax 2','Dmax 3','Dmax 4','Gualapack','TBA 1','TBA 2']
};
const MOTIVOS_DESVIO=['Manutenção / quebra','Falta de material','Aguardando qualidade','Setup atrasado','Reprogramação PCP','Falta de pessoas','Atraso base','Padronização','Reprocesso','Outro'];
function plusHoursLocal(value:string,hours:number){if(!value)return'';const d=new Date(value);if(Number.isNaN(d.getTime()))return'';return new Date(d.getTime()+hours*60*60*1000).toISOString().slice(0,16)}
function fmtDateTime(v?:string){if(!v)return'—';const d=new Date(v);return Number.isNaN(d.getTime())?v:d.toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',year:'numeric',hour:'2-digit',minute:'2-digit'})}
function fmtShort(v?:string){if(!v)return'—';const d=new Date(v);return Number.isNaN(d.getTime())?v:d.toLocaleString('pt-BR',{day:'2-digit',month:'2-digit',hour:'2-digit',minute:'2-digit'})}
function parsePassagem(d:Diario):PassagemV6|null{try{if(!d.resumo?.startsWith(V6_PREFIX))return null;return JSON.parse(d.resumo.slice(V6_PREFIX.length))}catch{return null}}
function classifyMachine(m:MachineEntry){const now=new Date();const next=m.proximoCip?new Date(m.proximoCip):null;const cipVencido=!!next&&!Number.isNaN(next.getTime())&&next<now;const venceLogo=!!next&&!Number.isNaN(next.getTime())&&next>=now&&(next.getTime()-now.getTime())<=12*60*60*1000;if(m.pcpStatus==='nao')return{status:'desvio' as const,reason:m.motivo||'PCP não seguido'};if(cipVencido)return{status:'desvio' as const,reason:'CIP vencido'};if(m.parada4h==='sim'&&m.cipRenovacao==='nao')return{status:'desvio' as const,reason:'Parada ≥4h sem CIP de renovação'};if(venceLogo)return{status:'atencao' as const,reason:'CIP vence em até 12h'};if(m.parada4h==='sim')return{status:'atencao' as const,reason:'Parada ≥4h registrada'};if((m.pessoas||'').trim())return{status:'atencao' as const,reason:'Aviso de pessoas/trocas'};return{status:'conforme' as const,reason:'Sem pendências'}}

function focusNextControl(current:HTMLElement|null){
  if(!current)return;
  const form=current.closest('.opGroupBody')||current.closest('section')||document.body;
  const controls=Array.from(form.querySelectorAll<HTMLElement>('input:not([readonly]), select, textarea, button.primary'))
    .filter(el=>!el.hasAttribute('disabled')&&el.offsetParent!==null);
  const idx=controls.indexOf(current);
  if(idx>=0&&idx<controls.length-1){
    setTimeout(()=>{const nextControl=controls[idx+1]; nextControl.focus(); if(nextControl instanceof HTMLInputElement) nextControl.select();},80);
  }
}
function SkuSelect({value,onChange,label,machine,autoAdvance=false}:{value:string;onChange:(v:string)=>void;label:string;machine:string;autoAdvance?:boolean}){
  const options=useMemo(()=>skuOptionsForMachine(machine),[machine]);
  const[query,setQuery]=useState(value||'');
  const[open,setOpen]=useState(false);
  useEffect(()=>{setQuery(value||'')},[value,machine]);
  const filtered=useMemo(()=>{
    const q=query.trim().toLocaleLowerCase('pt-BR');
    if(!q)return options;
    return options.filter(item=>item.toLocaleLowerCase('pt-BR').includes(q));
  },[options,query]);
  function choose(item:string,input?:HTMLInputElement|null){
    setQuery(item);setOpen(false);onChange(item);
    if(autoAdvance&&input)setTimeout(()=>focusNextControl(input),100);
  }
  const inputRef=React.useRef<HTMLInputElement|null>(null);
  return <label className="skuField">{label}<div className="skuCombo"><input
    ref={inputRef}
    value={query}
    placeholder="Toque para selecionar o SKU"
    autoComplete="off"
    readOnly
    onClick={()=>setOpen(true)}
    onFocus={()=>setOpen(true)}
    aria-expanded={open}
  /><button type="button" className="skuTrigger" onClick={()=>setOpen(true)} aria-label={`Selecionar ${label}`}>⌄</button></div>{open&&<div className="skuModal" role="dialog" aria-modal="true"><div className="skuModalBackdrop" onClick={()=>setOpen(false)}/><div className="skuModalPanel"><div className="skuModalHead"><div><b>{label}</b><span>{machine}</span></div><button type="button" className="iconBtn" onClick={()=>setOpen(false)}><X size={20}/></button></div><div className="skuSearch"><Search size={18}/><input autoFocus value={query} onChange={e=>setQuery(e.target.value)} placeholder="Pesquisar por nome ou código..."/></div><div className="skuOptions" role="listbox">{filtered.length?filtered.map(item=><button type="button" key={item} className={item==='Sem Programação'?'skuOption noSchedule':'skuOption'} onClick={()=>choose(item,inputRef.current)}>{item}</button>):<div className="skuEmpty">Nenhum SKU disponível para esta máquina.</div>}</div></div></div>}</label>
}

function operationalItems(diarios:Diario[], period?:(d:Diario)=>boolean):OperationalItem[]{const list:OperationalItem[]=[];diarios.filter(d=>period?period(d):true).forEach(d=>{const p=parsePassagem(d);if(!p)return;p.maquinas.forEach(m=>{const c=classifyMachine(m);list.push({record:d,payload:p,machine:m,status:c.status,reason:c.reason,turno:p.turno,area:p.area,machineName:m.maquina,criadoEm:p.criadoEm,lider:p.lider})})});return list.sort((a,b)=>new Date(b.criadoEm).getTime()-new Date(a.criadoEm).getTime())}
function latestItems(items:OperationalItem[]){const map=new Map<string,OperationalItem>();items.forEach(i=>{const k=`${i.area}|${i.machineName}|${i.turno}`;if(!map.has(k))map.set(k,i)});return Array.from(map.values())}
function StatusPill({status}:{status:OperationalItem['status']}){return <span className={'opPill '+status}>{status==='desvio'?'Desvio':status==='atencao'?'Atenção':'Conforme'}</span>}
function MachineDetail({item}:{item:OperationalItem}){const m=item.machine;return <div className="opDetailGrid"><div><small>PCP</small><b>{m.pcpStatus==='sim'?'Conforme':'Não conforme'}</b></div><div><small>Motivo</small><b>{m.pcpStatus==='nao'?(m.motivo||'—'):'—'}</b></div><div><small>SKU atual</small><b>{m.skuAtual}</b></div><div><small>SKU programado</small><b>{m.skuProgramado||m.skuAtual}</b></div><div><small>Programado</small><b>{m.programado}</b></div><div><small>Produzido</small><b>{m.produzido}</b></div><div className="span2"><small>Próximos SKUs / Sequência</small><b>{m.pcpStatus==='nao'?(m.novaSequencia||'—'):(m.proximosSkus||'—')}</b></div><div><small>Último CIP</small><b>{fmtShort(m.ultimoCip)}</b></div><div><small>Próximo CIP</small><b>{fmtShort(m.proximoCip)}</b></div><div><small>Fez CIP?</small><b>{m.fezCip==='sim'?'Sim':'Não'}</b></div><div><small>Parada ≥4h</small><b>{m.parada4h==='sim'?'Sim':'Não'}</b></div>{m.parada4h==='sim'&&<><div><small>Parada início</small><b>{fmtShort(m.paradaInicio)}</b></div><div><small>Parada retorno</small><b>{fmtShort(m.paradaFim)}</b></div><div className="span2"><small>Motivo parada/CIP</small><b>{m.paradaMotivo||m.cipMotivo||'—'}</b></div></>}<div className="span2"><small>Pessoas/trocas/avisos</small><b>{m.pessoas||'Sem trocas/avisos de pessoas.'}</b></div><div className="span2 opObs"><small>Observações</small><b>{m.observacoes||'Sem observações gerais.'}</b></div><div className="span2"><small>Registro</small><b>{item.lider} • {fmtDateTime(item.criadoEm)}</b></div></div>}
function FilterCards({filter,setFilter,items}:{filter:CritFilter;setFilter:(f:CritFilter)=>void;items:OperationalItem[]}){return <div className="opFilters"><button className={filter==='todos'?'active':''} onClick={()=>setFilter('todos')}><b>{items.length}</b><span>Todos</span></button><button className={filter==='desvios'?'active':''} onClick={()=>setFilter('desvios')}><b>{items.filter(i=>i.status==='desvio').length}</b><span>Desvios</span></button><button className={filter==='atencoes'?'active':''} onClick={()=>setFilter('atencoes')}><b>{items.filter(i=>i.status==='atencao').length}</b><span>Atenções</span></button></div>}
function OperationalBoard({items,title='Quadro operacional'}:{items:OperationalItem[];title?:string}){const[area,setArea]=useState<AreaEnvase>('Envase 1'),[view,setView]=useState<ViewMode>('maquina'),[filter,setFilter]=useState<CritFilter>('todos'),[open,setOpen]=useState<Record<string,boolean>>({});const areaItems=items.filter(i=>i.area===area);const shown=filter==='desvios'?areaItems.filter(i=>i.status==='desvio'):filter==='atencoes'?areaItems.filter(i=>i.status==='atencao'):areaItems;const machines=DEFAULT_MACHINES[area];const turnos=['1º Turno','2º Turno','3º Turno'];function itemKey(i:OperationalItem){return`${i.area}-${i.machineName}-${i.turno}-${i.record.id}`}function toggle(k:string){setOpen(o=>({...o,[k]:!o[k]}))}return <div className="opBoard"><div className="opHead"><div><h3>{title}</h3><p>Visualize a passagem real por máquina ou por turno.</p></div><span className="pill ok">{shown.length} itens</span></div><div className="opSwitch"><button className={area==='Envase 1'?'active':''} onClick={()=>setArea('Envase 1')}>Envase 1</button><button className={area==='Envase 2'?'active':''} onClick={()=>setArea('Envase 2')}>Envase 2</button></div><FilterCards filter={filter} setFilter={setFilter} items={areaItems}/><div className="opSwitch small"><button className={view==='maquina'?'active':''} onClick={()=>setView('maquina')}>Visão por máquina</button><button className={view==='turno'?'active':''} onClick={()=>setView('turno')}>Visão por turno</button></div>{filter!=='todos'?<div className="attentionBox"><h4>{filter==='desvios'?'Itens com desvio':'Itens que demandam atenção'}</h4><p>Toque em cada item abaixo para expandir as informações exatamente no local.</p>{shown.length===0&&<div className="emptyState">Nenhum item encontrado.</div>}{shown.map(i=>{const k=itemKey(i);return <div className="opRow" key={k} onClick={()=>toggle(k)}><div className="opRowTop"><div><b>{i.machineName} • {i.turno}</b><span>{i.machine.skuAtual} • {i.reason}</span></div><StatusPill status={i.status}/></div>{open[k]&&<MachineDetail item={i}/>}</div>})}</div>:view==='maquina'?<div className="opList">{machines.map(machine=>{const its=turnos.map(t=>areaItems.find(i=>i.machineName===machine&&i.turno===t)).filter(Boolean) as OperationalItem[];const worst=its.find(i=>i.status==='desvio')? 'desvio':its.find(i=>i.status==='atencao')?'atencao':'conforme';const k=`m-${area}-${machine}`;return <div className="opGroup" key={machine}><button className="opGroupHeader" onClick={()=>toggle(k)}><div><b>{machine}</b><span>T1, T2 e T3 dentro da máquina</span></div><StatusPill status={worst as any}/><span>▼</span></button>{open[k]&&<div className="opGroupBody">{turnos.map(t=>{const i=areaItems.find(x=>x.machineName===machine&&x.turno===t);if(!i)return <div className="opEmptyTurn" key={t}>{t}: sem lançamento</div>;const ik=itemKey(i);return <div className="opRow" key={ik} onClick={()=>toggle(ik)}><div className="opRowTop"><div><b>{t}</b><span>{i.machine.skuAtual} • {i.reason}</span></div><StatusPill status={i.status}/></div>{open[ik]&&<MachineDetail item={i}/>}</div>})}</div>}</div>})}</div>:<div className="opList">{turnos.map(t=>{const turnItems=areaItems.filter(i=>i.turno===t);const worst=turnItems.find(i=>i.status==='desvio')?'desvio':turnItems.find(i=>i.status==='atencao')?'atencao':'conforme';const k=`t-${area}-${t}`;return <div className="opGroup" key={t}><button className="opGroupHeader" onClick={()=>toggle(k)}><div><b>{t}</b><span>{turnItems.length} máquinas lançadas</span></div><StatusPill status={worst as any}/><span>▼</span></button>{open[k]&&<div className="opGroupBody">{machines.map(machine=>{const i=turnItems.find(x=>x.machineName===machine);if(!i)return <div className="opEmptyTurn" key={machine}>{machine}: sem lançamento</div>;const ik=itemKey(i);return <div className="opRow" key={ik} onClick={()=>toggle(ik)}><div className="opRowTop"><div><b>{machine}</b><span>{i.machine.skuAtual} • {i.reason}</span></div><StatusPill status={i.status}/></div>{open[ik]&&<MachineDetail item={i}/>}</div>})}</div>}</div>})}</div>}</div>}
function HomePage({tick}:{tick:number}){const[diarios,setD]=useState<Diario[]>([]);useEffect(()=>{listDiarios().then(setD)},[tick]);const hoje=new Date().toISOString().slice(0,10);const items=latestItems(operationalItems(diarios,d=>d.data===hoje));return <section className="page"><div className="pageTitle"><h2>Hoje</h2><p>Passagem real de turno: o que aconteceu em cada máquina, por turno.</p></div><OperationalBoard items={items} title="Hoje — Envase"/></section>}
function newEntry(machine:string):MachineEntry{return{maquina:machine,pcpStatus:'sim',skuAtual:'',programado:'',produzido:'',proximosSkus:'',ultimoCip:'',proximoCip:'',fezCip:'nao',parada4h:'nao',observacoes:'',pessoas:''}}
function NovoDiario({onSaved}:{onSaved:()=>void}){
  const DRAFT_KEY='dbt_v651_novo_draft';
  const steps=['PCP','Produção','CIP','Comunicação'];
  const savedDraft=useMemo(()=>{try{return JSON.parse(localStorage.getItem(DRAFT_KEY)||'null')}catch{return null}},[]);
  const draftArea:AreaEnvase=savedDraft?.area==='Envase 2'?'Envase 2':'Envase 1';
  const[area,setArea]=useState<AreaEnvase>(draftArea);
  const[turno,setTurno]=useState(savedDraft?.turno||'1º Turno');
  const[data,setData]=useState(savedDraft?.data||new Date().toISOString().slice(0,10));
  const[obs,setObs]=useState(savedDraft?.obs||'');
  const[entries,setEntries]=useState<MachineEntry[]>(savedDraft?.entries||DEFAULT_MACHINES[draftArea].map(newEntry));
  const[machineIndex,setMachineIndex]=useState(savedDraft?.machineIndex||0);
  const[step,setStep]=useState(savedDraft?.step||0);
  const[error,setError]=useState('');
  const[saving,setSaving]=useState(false);
  const current=entries[machineIndex]||entries[0];
  useEffect(()=>{localStorage.setItem(DRAFT_KEY,JSON.stringify({area,turno,data,obs,entries,machineIndex,step}))},[area,turno,data,obs,entries,machineIndex,step]);
  function changeArea(a:AreaEnvase){setArea(a);setEntries(DEFAULT_MACHINES[a].map(newEntry));setMachineIndex(0);setStep(0);setError('')}
  function upd(machine:string,patch:Partial<MachineEntry>){setEntries(es=>es.map(e=>e.maquina===machine?{...e,...patch}:e))}
  function setLastCip(machine:string,val:string){upd(machine,{ultimoCip:val,proximoCip:plusHoursLocal(val,72)})}
  function requiredForStep(e:MachineEntry,n:number){
    if(n===0){if(!e.pcpStatus)return'Selecione se seguiu o PCP';if(e.pcpStatus==='nao'){if(!e.motivo)return'Selecione o motivo';if(!e.ocorrido)return'Descreva o que aconteceu';if(!e.skuProgramado)return'Selecione o SKU programado'}}
    if(n===1){if(!e.skuAtual)return'Selecione o SKU rodando';if(!e.programado)return'Informe o programado';if(!e.produzido)return'Informe o produzido';if(e.pcpStatus==='sim'&&!e.proximosSkus)return'Selecione o próximo SKU';if(e.pcpStatus==='nao'&&!e.novaSequencia)return'Selecione a nova sequência'}
    if(n===2){if(!e.ultimoCip)return'Informe o último CIP';if(!e.proximoCip)return'Próximo CIP não calculado';if(!e.fezCip)return'Informe se fez CIP';if(!e.parada4h)return'Informe se houve parada ≥4h';if(e.parada4h==='sim'){if(!e.paradaInicio)return'Informe o início da parada';if(!e.paradaFim)return'Informe o retorno/previsão';if(!e.paradaMotivo)return'Informe o motivo da parada';if(!e.cipRenovacao)return'Informe se fez CIP de renovação';if(e.cipRenovacao==='nao'&&!e.cipMotivo)return'Justifique a não realização do CIP'}const expired=e.proximoCip&&new Date(e.proximoCip)<new Date();if(expired&&!e.cipMotivo)return'Justifique o CIP vencido/fora do prazo'}
    if(n===3){if(!e.pessoas)return'Informe pessoas/trocas ou “Sem trocas/avisos”';if(!e.observacoes)return'Informe observações ou “Sem observações”'}
    return''
  }
  function machineComplete(e:MachineEntry){return steps.every((_,i)=>!requiredForStep(e,i))}
  function focusFirstInvalid(){setTimeout(()=>{const root=document.querySelector('.wizardStage');const el=root?.querySelector<HTMLElement>('input:invalid,select:invalid,textarea:invalid,input[value=""],textarea:empty');(el||root)?.scrollIntoView({behavior:'smooth',block:'center'});el?.focus?.()},100)}
  function next(){const msg=requiredForStep(current,step);if(msg){setError(msg);focusFirstInvalid();return}setError('');if(step<steps.length-1){setStep(step+1);window.scrollTo({top:0,behavior:'smooth'});return}if(machineIndex<entries.length-1){setMachineIndex(machineIndex+1);setStep(0);window.scrollTo({top:0,behavior:'smooth'});return}}
  function back(){setError('');if(step>0){setStep(step-1);return}if(machineIndex>0){setMachineIndex(machineIndex-1);setStep(steps.length-1)}}
  function goTo(machine:number,stage=0){setMachineIndex(machine);setStep(stage);setError('');window.scrollTo({top:0,behavior:'smooth'})}
  async function salvar(){for(let mi=0;mi<entries.length;mi++){for(let si=0;si<steps.length;si++){const msg=requiredForStep(entries[mi],si);if(msg){goTo(mi,si);setError(`${entries[mi].maquina}: ${msg}`);return}}}setSaving(true);try{const me=currentUser()!;const payload:PassagemV6={version:'v6-envase',area,turno,data,lider:me.nome,liderId:me.id,criadoEm:new Date().toISOString(),maquinas:entries,observacoesGerais:obs||'Sem observações gerais.'};await saveDiario({data,turno,setor_nome:area,lider_id:me.id,lider_nome:me.nome,status:'Finalizado',resumo:V6_PREFIX+JSON.stringify(payload)});localStorage.removeItem(DRAFT_KEY);onSaved()}finally{setSaving(false)}}
  const progress=Math.round(((machineIndex*steps.length+step+1)/(entries.length*steps.length))*100);
  return <section className="page newPassageWizard"><div className="wizardTop"><div><span className="wizardEyebrow">Nova passagem de turno</span><h2>{current.maquina}</h2><p>{area} • {turno} • Etapa {step+1} de {steps.length}</p></div><div className="wizardProgressCircle">{progress}%</div></div><div className="wizardProgress"><span style={{width:`${progress}%`}}/></div><div className="wizardSetup"><label>Data<input type="date" value={data} onChange={e=>setData(e.target.value)}/></label><label>Turno<select value={turno} onChange={e=>setTurno(e.target.value)}><option>1º Turno</option><option>2º Turno</option><option>3º Turno</option></select></label><div className="opSwitch"><button className={area==='Envase 1'?'active':''} onClick={()=>changeArea('Envase 1')}>Envase 1</button><button className={area==='Envase 2'?'active':''} onClick={()=>changeArea('Envase 2')}>Envase 2</button></div></div><div className="machineStrip" aria-label="Máquinas">{entries.map((e,i)=><button key={e.maquina} onClick={()=>goTo(i,0)} className={(i===machineIndex?'active ':'')+(machineComplete(e)?'done':'')}><span>{i+1}</span><b>{e.maquina}</b>{machineComplete(e)&&<CheckCircle2 size={16}/>}</button>)}</div><div className="wizardSteps">{steps.map((s,i)=><button key={s} className={i===step?'active':i<step?'done':''} onClick={()=>goTo(machineIndex,i)}><span>{i+1}</span>{s}</button>)}</div>{error&&<div className="err wizardError">{error}</div>}<div className="card wizardStage">
    {step===0&&<><div className="stageHeader"><ShieldCheck/><div><h3>Programação PCP</h3><p>Registre rapidamente se a sequência foi seguida.</p></div></div><label>Seguiu a programação PCP?<select value={current.pcpStatus} onChange={e=>{upd(current.maquina,{pcpStatus:e.target.value as PcpStatus});setTimeout(()=>focusNextControl(e.currentTarget),80)}}><option value="sim">Sim, conforme PCP</option><option value="nao">Não, houve alteração</option></select></label>{current.pcpStatus==='nao'&&<div className="conditionalPanel"><label>Motivo<select required value={current.motivo||''} onChange={e=>{upd(current.maquina,{motivo:e.target.value});setTimeout(()=>focusNextControl(e.currentTarget),80)}}><option value="">Selecione</option>{MOTIVOS_DESVIO.map(m=><option key={m}>{m}</option>)}</select></label><label>O que aconteceu?<textarea required value={current.ocorrido||''} onChange={e=>upd(current.maquina,{ocorrido:e.target.value})} placeholder="Descreva em poucas palavras"/></label><SkuSelect machine={current.maquina} label="SKU programado" value={current.skuProgramado||''} onChange={v=>upd(current.maquina,{skuProgramado:v})} autoAdvance/></div>}</>}
    {step===1&&<><div className="stageHeader"><Factory/><div><h3>Produção</h3><p>SKU atual, programado, produzido e sequência.</p></div></div><SkuSelect machine={current.maquina} label="SKU rodando" value={current.skuAtual} onChange={v=>upd(current.maquina,{skuAtual:v})} autoAdvance/><div className="quantityGrid"><label>Programado<input required inputMode="decimal" value={current.programado} onChange={e=>upd(current.maquina,{programado:e.target.value})} onKeyDown={e=>{if(e.key==='Enter'){e.preventDefault();focusNextControl(e.currentTarget)}}} placeholder="Ex.: 12.000 un"/></label><label>Produzido<input required inputMode="decimal" value={current.produzido} onChange={e=>upd(current.maquina,{produzido:e.target.value})} onKeyDown={e=>{if(e.key==='Enter'){e.preventDefault();focusNextControl(e.currentTarget)}}} placeholder="Ex.: 8.450 un"/></label></div>{current.pcpStatus==='sim'?<SkuSelect machine={current.maquina} label="Próximo SKU" value={current.proximosSkus||''} onChange={v=>upd(current.maquina,{proximosSkus:v})} autoAdvance/>:<SkuSelect machine={current.maquina} label="Nova sequência / próximo SKU" value={current.novaSequencia||''} onChange={v=>upd(current.maquina,{novaSequencia:v})} autoAdvance/>}</>}
    {step===2&&<><div className="stageHeader"><RefreshCcw/><div><h3>CIP e parada</h3><p>Validade de 72h e renovação após parada contínua.</p></div></div><div className="cipGrid"><label>Último CIP<input required type="datetime-local" value={current.ultimoCip} onChange={e=>setLastCip(current.maquina,e.target.value)}/></label><label>Próximo CIP<input readOnly value={current.proximoCip}/></label></div>{current.proximoCip&&<div className={(new Date(current.proximoCip)<new Date())?'cipStatus danger':'cipStatus ok'}>{new Date(current.proximoCip)<new Date()?'CIP vencido — justificativa obrigatória':'CIP dentro do prazo'}</div>}<div className="choiceGrid"><label>Fez CIP?<select value={current.fezCip} onChange={e=>upd(current.maquina,{fezCip:e.target.value as any})}><option value="nao">Não</option><option value="sim">Sim</option></select></label><label>Parou por 4h ou mais?<select value={current.parada4h} onChange={e=>upd(current.maquina,{parada4h:e.target.value as any})}><option value="nao">Não</option><option value="sim">Sim</option></select></label></div>{current.parada4h==='sim'&&<div className="conditionalPanel"><div className="cipGrid"><label>Início da parada<input required type="datetime-local" value={current.paradaInicio||''} onChange={e=>upd(current.maquina,{paradaInicio:e.target.value})}/></label><label>Retorno/previsão<input required type="datetime-local" value={current.paradaFim||''} onChange={e=>upd(current.maquina,{paradaFim:e.target.value})}/></label></div><label>Motivo da parada<input required value={current.paradaMotivo||''} onChange={e=>upd(current.maquina,{paradaMotivo:e.target.value})}/></label><label>CIP de renovação realizado?<select required value={current.cipRenovacao||''} onChange={e=>upd(current.maquina,{cipRenovacao:e.target.value as any})}><option value="">Selecione</option><option value="sim">Sim</option><option value="nao">Não</option></select></label></div>}<label>Justificativa do CIP, quando aplicável<textarea value={current.cipMotivo||''} onChange={e=>upd(current.maquina,{cipMotivo:e.target.value})} placeholder="Obrigatório quando vencido ou renovação não realizada"/></label></>}
    {step===3&&<><div className="stageHeader"><Users/><div><h3>Comunicação do turno</h3><p>Registre apenas o essencial para o próximo líder.</p></div></div><label>Pessoas, trocas e avisos<textarea required value={current.pessoas||''} onChange={e=>upd(current.maquina,{pessoas:e.target.value})} placeholder="Ex.: Sem trocas/avisos"/></label><button type="button" className="quickFill" onClick={()=>upd(current.maquina,{pessoas:'Sem trocas/avisos.'})}>Sem trocas/avisos</button><label>Observações da máquina<textarea required value={current.observacoes} onChange={e=>upd(current.maquina,{observacoes:e.target.value})} placeholder="Ex.: Sem observações"/></label><button type="button" className="quickFill" onClick={()=>upd(current.maquina,{observacoes:'Sem observações.'})}>Sem observações</button></>}
  </div><div className="wizardActions"><button type="button" className="secondary" onClick={back} disabled={machineIndex===0&&step===0}>Voltar</button>{machineIndex===entries.length-1&&step===steps.length-1?<button type="button" className="primary" onClick={salvar} disabled={saving}>{saving?'Salvando...':'Finalizar passagem'}</button>:<button type="button" className="primary" onClick={next}>Continuar</button>}</div><details className="generalNotes"><summary>Observações gerais da passagem</summary><textarea value={obs} onChange={e=>setObs(e.target.value)} placeholder="Resumo geral do turno, se houver."/></details><p className="draftHint">Rascunho salvo automaticamente neste dispositivo.</p></section>
}

function Historico(){const[ds,setD]=useState<Diario[]>([]),[modo,setModo]=useState<'dia'|'semana'|'mes'>('dia');useEffect(()=>{listDiarios().then(setD)},[]);const now=new Date();function period(d:Diario){const dt=new Date(d.data+'T00:00:00');if(modo==='dia')return d.data===now.toISOString().slice(0,10);if(modo==='mes')return dt.getMonth()===now.getMonth()&&dt.getFullYear()===now.getFullYear();const diff=(now.getTime()-dt.getTime())/(1000*60*60*24);return diff>=0&&diff<7}const items=latestItems(operationalItems(ds,period));return <section className="page"><div className="pageTitle"><h2>Histórico</h2><p>Compilado por dia, semana e mês com a mesma visão operacional.</p></div><div className="opSwitch"><button className={modo==='dia'?'active':''} onClick={()=>setModo('dia')}>Dia</button><button className={modo==='semana'?'active':''} onClick={()=>setModo('semana')}>Semana</button><button className={modo==='mes'?'active':''} onClick={()=>setModo('mes')}>Mês</button></div><OperationalBoard items={items} title={`Histórico — ${modo}`}/></section>}
function Admin(){if(!isAdmin())return <section className="page"><div className="card"><h2>Acesso restrito</h2><p>Esta área aparece somente para administradores.</p></div></section>;const[area,setArea]=useState<'usuarios'|'setores'|'maquinas'|'turnos'|'logs'|'config'>('usuarios');return <section className="page adminPage"><div className="pageTitle"><h2>Administração</h2><p>Painel de controle enterprise: usuários, setores, máquinas, turnos, logs e configurações.</p></div><div className="adminTabs"><button className={area==='usuarios'?'active':''} onClick={()=>setArea('usuarios')}><Users/> Usuários</button><button className={area==='setores'?'active':''} onClick={()=>setArea('setores')}><Factory/> Setores</button><button className={area==='maquinas'?'active':''} onClick={()=>setArea('maquinas')}><Settings2/> Máquinas</button><button className={area==='turnos'?'active':''} onClick={()=>setArea('turnos')}><Clock3/> Turnos</button><button className={area==='logs'?'active':''} onClick={()=>setArea('logs')}><Activity/> Logs</button><button className={area==='config'?'active':''} onClick={()=>setArea('config')}><SlidersHorizontal/> Config.</button></div>{area==='usuarios'&&<UsuariosAdmin/>}{area==='setores'&&<SetoresAdmin/>}{area==='maquinas'&&<MaquinasAdmin/>}{area==='turnos'&&<TurnosAdmin/>}{area==='logs'&&<LogsAdmin/>}{area==='config'&&<ConfigAdmin/>}</section>}
function EmptyState({text}:{text:string}){return <div className="emptyState"><Database size={28}/><span>{text}</span></div>}
function UsuariosAdmin(){const[items,setItems]=useState<Usuario[]>([]),[nome,setNome]=useState(''),[usuario,setUsuario]=useState(''),[setor,setorSet]=useState(''),[cargo,setCargo]=useState(''),[perfil,setPerfil]=useState<'administrador'|'usuario'>('usuario'),[ativo,setAtivo]=useState(true),[busca,setBusca]=useState(''),[status,setStatus]=useState('todos'),[perfilFiltro,setPerfilFiltro]=useState('todos'),[msg,setMsg]=useState(''),[edit,setEdit]=useState<Usuario|null>(null);async function load(){setItems(await listUsuarios())}useEffect(()=>{load()},[]);useEffect(()=>{if(!edit)setUsuario(makeUsername(nome))},[nome,edit]);const filtrados=useMemo(()=>items.filter(u=>`${u.nome} ${u.usuario} ${u.setor} ${u.cargo} ${u.perfil}`.toLowerCase().includes(busca.toLowerCase())).filter(u=>status==='todos'||(status==='ativo'?u.ativo:!u.ativo)).filter(u=>perfilFiltro==='todos'||u.perfil===perfilFiltro),[items,busca,status,perfilFiltro]);function limpar(){setNome('');setUsuario('');setorSet('');setCargo('');setPerfil('usuario');setAtivo(true);setEdit(null)}function editar(u:Usuario){setEdit(u);setNome(u.nome);setUsuario(u.usuario);setorSet(u.setor);setCargo(u.cargo);setPerfil(u.perfil);setAtivo(u.ativo);window.scrollTo({top:0,behavior:'smooth'})}async function salvar(){try{if(!nome||!usuario||!setor||!cargo)return alert('Preencha nome, usuário, setor e cargo.');const base:any={id:edit?.id,nome,usuario:usuario.toLowerCase().trim(),setor,cargo,perfil,ativo,trocar_senha:edit?.trocar_senha??true};if(!edit)base.senha='123456';await saveUsuario(base);setMsg(edit?`Usuário ${usuario} atualizado.`:`Usuário ${usuario} cadastrado com senha provisória 123456.`);limpar();await load()}catch(err:any){console.error(err);alert('Não foi possível salvar o usuário. Detalhe: '+(err?.message||JSON.stringify(err)))}}async function toggle(u:Usuario){await saveUsuario({...u,ativo:!u.ativo});setMsg(`${u.nome} foi ${u.ativo?'inativado':'ativado'}.`);load()}async function resetSenha(u:Usuario){if(!confirm(`Resetar senha de ${u.nome} para 123456?`))return;await saveUsuario({...u,senha:'123456',trocar_senha:true});setMsg(`Senha de ${u.nome} resetada para 123456.`);load()}async function excluir(u:Usuario){if(!confirm(`Excluir ${u.nome}? Recomenda-se inativar quando já houver histórico.`))return;await deleteUsuario(u.id);setMsg(`Usuário ${u.nome} excluído.`);load()}return <div className="card adminCard"><div className="sectionHeader"><div><h3>Usuários</h3><p>Cadastre, edite, ative/inative, exclua e resete senha dos usuários.</p></div><ShieldCheck size={24}/></div><div className="editBanner">{edit?<><Edit3 size={18}/> Editando usuário: <b>{edit.nome}</b></>:<><UserPlus size={18}/> Novo usuário</>}</div><div className="formGrid adminForm"><label>Nome completo<input placeholder="Ex.: Vinícius Mendonça" value={nome} onChange={e=>setNome(e.target.value)}/></label><label>Usuário<input placeholder="ex.: vinicius.mendonca" value={usuario} onChange={e=>setUsuario(e.target.value.toLowerCase())}/></label><label>Setor<input placeholder="Ex.: Envase 1" value={setor} onChange={e=>setorSet(e.target.value)}/></label><label>Cargo<input placeholder="Ex.: Líder" value={cargo} onChange={e=>setCargo(e.target.value)}/></label><label>Perfil<select value={perfil} onChange={e=>setPerfil(e.target.value as any)}><option value="usuario">usuario</option><option value="administrador">administrador</option></select></label><label>Status<select value={ativo?'ativo':'inativo'} onChange={e=>setAtivo(e.target.value==='ativo')}><option value="ativo">ativo</option><option value="inativo">inativo</option></select></label></div><div className="formActions"><button type="button" className="primary" onClick={salvar}>{edit?<><Save size={18}/> Salvar alterações</>:<><UserPlus size={18}/> Cadastrar usuário</>}</button>{edit&&<button type="button" className="secondary" onClick={limpar}><X size={18}/> Cancelar edição</button>}</div>{msg&&<div className="successMsg">{msg}</div>}<div className="smartFilters"><div className="searchBox"><Search size={18}/><input placeholder="Buscar por nome, usuário, setor, cargo..." value={busca} onChange={e=>setBusca(e.target.value)}/></div><select value={perfilFiltro} onChange={e=>setPerfilFiltro(e.target.value)}><option value="todos">Todos os perfis</option><option value="administrador">Administradores</option><option value="usuario">Usuários</option></select><select value={status} onChange={e=>setStatus(e.target.value)}><option value="todos">Todos os status</option><option value="ativo">Ativos</option><option value="inativo">Inativos</option></select></div>{!filtrados.length&&<EmptyState text="Nenhum usuário encontrado."/>}<div className="userList">{filtrados.map(u=><article className="userRow" key={u.id}><div className="avatar">{u.nome.split(' ').map(x=>x[0]).slice(0,2).join('').toUpperCase()}</div><div className="userInfo"><b>{u.nome}</b><span>{u.usuario} • {u.setor} • {u.cargo}</span><div className="badges"><em>{u.perfil}</em><em className={u.ativo?'badgeOk':'badgeOff'}>{u.ativo?'ativo':'inativo'}</em>{u.trocar_senha&&<em>trocar senha</em>}</div></div><div className="rowActions"><button type="button" className="secondary" onClick={()=>editar(u)}><Edit3 size={16}/> Editar</button><button type="button" className={u.ativo?'secondary dangerSoft':'secondary okSoft'} onClick={()=>toggle(u)}>{u.ativo?<><Power size={16}/> Inativar</>:<><CheckCircle2 size={16}/> Ativar</>}</button><button type="button" className="secondary" onClick={()=>resetSenha(u)}><KeyRound size={16}/> Resetar</button><button type="button" className="secondary dangerSoft" onClick={()=>excluir(u)}><Trash2 size={16}/> Excluir</button></div></article>)}</div></div>}
function SetoresAdmin(){const[items,setItems]=useState<Setor[]>([]),[nome,setNome]=useState(''),[tipo,setTipo]=useState(''),[ativo,setAtivo]=useState(true),[edit,setEdit]=useState<Setor|null>(null),[busca,setBusca]=useState(''),[status,setStatus]=useState('todos'),[msg,setMsg]=useState('');async function load(){setItems(await listSetores())}useEffect(()=>{load()},[]);const filtrados=items.filter(s=>`${s.nome} ${s.tipo}`.toLowerCase().includes(busca.toLowerCase())).filter(s=>status==='todos'||(status==='ativo'?s.ativo:!s.ativo));function limpar(){setNome('');setTipo('');setAtivo(true);setEdit(null)}function editar(s:Setor){setEdit(s);setNome(s.nome);setTipo(s.tipo||'');setAtivo(s.ativo);window.scrollTo({top:0,behavior:'smooth'})}async function salvar(){if(!nome)return alert('Informe o nome do setor.');await saveSetor({id:edit?.id,nome,tipo,ativo});setMsg(edit?`Setor ${nome} atualizado.`:`Setor ${nome} cadastrado.`);limpar();load()}async function toggle(s:Setor){await saveSetor({...s,ativo:!s.ativo});load()}async function excluir(s:Setor){if(!confirm(`Excluir setor ${s.nome}?`))return;await deleteSetor(s.id);load()}return <div className="card adminCard"><div className="sectionHeader"><div><h3>Setores</h3><p>Cadastre, edite, ative/inative e filtre setores.</p></div><Factory size={24}/></div><div className="editBanner">{edit?<><Edit3 size={18}/> Editando setor: <b>{edit.nome}</b></>:<>Novo setor</>}</div><div className="formGrid adminForm"><label>Nome do setor<input placeholder="Ex.: Envase 1" value={nome} onChange={e=>setNome(e.target.value)}/></label><label>Tipo / Grupo<input placeholder="Ex.: Produção" value={tipo} onChange={e=>setTipo(e.target.value)}/></label><label>Status<select value={ativo?'ativo':'inativo'} onChange={e=>setAtivo(e.target.value==='ativo')}><option value="ativo">ativo</option><option value="inativo">inativo</option></select></label></div><div className="formActions"><button type="button" className="primary" onClick={salvar}>{edit?<><Save size={18}/> Salvar setor</>:<>Cadastrar setor</>}</button>{edit&&<button type="button" className="secondary" onClick={limpar}><X size={18}/> Cancelar</button>}</div>{msg&&<div className="successMsg">{msg}</div>}<div className="smartFilters"><div className="searchBox"><Search size={18}/><input placeholder="Buscar setor ou grupo..." value={busca} onChange={e=>setBusca(e.target.value)}/></div><select value={status} onChange={e=>setStatus(e.target.value)}><option value="todos">Todos</option><option value="ativo">Ativos</option><option value="inativo">Inativos</option></select></div><div className="compactList">{filtrados.map(s=><div className="compactRow" key={s.id}><span>{s.nome}</span><small>{s.tipo||'Sem grupo'}</small><b className={s.ativo?'txtOk':'txtOff'}>{s.ativo?'ativo':'inativo'}</b><button className="secondary" onClick={()=>editar(s)}><Edit3 size={16}/> Editar</button><button className="secondary" onClick={()=>toggle(s)}>{s.ativo?'Inativar':'Ativar'}</button><button className="secondary dangerSoft" onClick={()=>excluir(s)}><Trash2 size={16}/> Excluir</button></div>)}</div></div>}
function MaquinasAdmin(){const[setores,setSetores]=useState<Setor[]>([]),[items,setItems]=useState<Maquina[]>([]),[nome,setNome]=useState(''),[codigo,setCodigo]=useState(''),[ordem,setOrdem]=useState(0),[sid,setSid]=useState(''),[ativo,setAtivo]=useState(true),[edit,setEdit]=useState<Maquina|null>(null),[busca,setBusca]=useState(''),[setorFiltro,setSetorFiltro]=useState('todos'),[status,setStatus]=useState('todos'),[msg,setMsg]=useState('');async function load(){setSetores(await listSetores());setItems(await listMaquinas())}useEffect(()=>{load()},[]);const filtrados=items.filter(m=>`${m.nome} ${m.codigo} ${setores.find(s=>s.id===m.setor_id)?.nome||''}`.toLowerCase().includes(busca.toLowerCase())).filter(m=>setorFiltro==='todos'||m.setor_id===setorFiltro).filter(m=>status==='todos'||(status==='ativo'?m.ativo:!m.ativo));function limpar(){setNome('');setCodigo('');setOrdem(0);setSid('');setAtivo(true);setEdit(null)}function editar(m:Maquina){setEdit(m);setNome(m.nome);setCodigo(m.codigo||'');setOrdem(m.ordem||0);setSid(m.setor_id);setAtivo(m.ativo);window.scrollTo({top:0,behavior:'smooth'})}async function salvar(){if(!sid||!nome)return alert('Informe setor e máquina.');await saveMaquina({id:edit?.id,nome,codigo,ordem,setor_id:sid,ativo});setMsg(edit?`Máquina ${nome} atualizada.`:`Máquina ${nome} cadastrada.`);limpar();load()}async function toggle(m:Maquina){await saveMaquina({...m,ativo:!m.ativo});load()}async function excluir(m:Maquina){if(!confirm(`Excluir máquina ${m.nome}?`))return;await deleteMaquina(m.id);load()}return <div className="card adminCard"><div className="sectionHeader"><div><h3>Máquinas</h3><p>Cadastre, edite, troque de setor, ordene e filtre máquinas.</p></div><Factory size={24}/></div><div className="editBanner">{edit?<><Edit3 size={18}/> Editando máquina: <b>{edit.nome}</b></>:<>Nova máquina</>}</div><div className="formGrid adminForm"><label>Setor<select value={sid} onChange={e=>setSid(e.target.value)}><option value="">Selecione o setor</option>{setores.map(s=><option key={s.id} value={s.id}>{s.nome}</option>)}</select></label><label>Nome da máquina<input placeholder="Ex.: Serac 2" value={nome} onChange={e=>setNome(e.target.value)}/></label><label>Código / TAG<input placeholder="Opcional" value={codigo} onChange={e=>setCodigo(e.target.value)}/></label><label>Ordem<input type="number" value={ordem} onChange={e=>setOrdem(Number(e.target.value))}/></label><label>Status<select value={ativo?'ativo':'inativo'} onChange={e=>setAtivo(e.target.value==='ativo')}><option value="ativo">ativo</option><option value="inativo">inativo</option></select></label></div><div className="formActions"><button type="button" className="primary" onClick={salvar}>{edit?<><Save size={18}/> Salvar máquina</>:<>Cadastrar máquina</>}</button>{edit&&<button type="button" className="secondary" onClick={limpar}><X size={18}/> Cancelar</button>}</div>{msg&&<div className="successMsg">{msg}</div>}<div className="smartFilters"><div className="searchBox"><Search size={18}/><input placeholder="Buscar máquina, código ou setor..." value={busca} onChange={e=>setBusca(e.target.value)}/></div><select value={setorFiltro} onChange={e=>setSetorFiltro(e.target.value)}><option value="todos">Todos os setores</option>{setores.map(s=><option key={s.id} value={s.id}>{s.nome}</option>)}</select><select value={status} onChange={e=>setStatus(e.target.value)}><option value="todos">Todos</option><option value="ativo">Ativas</option><option value="inativo">Inativas</option></select></div><div className="compactList">{filtrados.map(m=><div className="compactRow machineRow" key={m.id}><span>{m.nome}</span><small>{setores.find(s=>s.id===m.setor_id)?.nome||'Sem setor'} {m.codigo?`• ${m.codigo}`:''}</small><b className={m.ativo?'txtOk':'txtOff'}>{m.ativo?'ativo':'inativo'}</b><button className="secondary" onClick={()=>editar(m)}><Edit3 size={16}/> Editar</button><button className="secondary" onClick={()=>toggle(m)}>{m.ativo?'Inativar':'Ativar'}</button><button className="secondary dangerSoft" onClick={()=>excluir(m)}><Trash2 size={16}/> Excluir</button></div>)}</div></div>}
function TurnosAdmin(){const[items,setItems]=useState<Turno[]>([]),[nome,setNome]=useState(''),[inicio,setInicio]=useState('06:00'),[fim,setFim]=useState('14:00'),[ativo,setAtivo]=useState(true),[edit,setEdit]=useState<Turno|null>(null),[busca,setBusca]=useState('');async function load(){setItems(await listTurnos())}useEffect(()=>{load()},[]);const filtrados=items.filter(t=>`${t.nome} ${t.inicio} ${t.fim}`.toLowerCase().includes(busca.toLowerCase()));function limpar(){setNome('');setInicio('06:00');setFim('14:00');setAtivo(true);setEdit(null)}function editar(t:Turno){setEdit(t);setNome(t.nome);setInicio(t.inicio);setFim(t.fim);setAtivo(t.ativo)}async function salvar(){try{if(!nome)return alert('Informe o nome do turno.');await saveTurno({id:edit?.id,nome,inicio,fim,ativo});limpar();await load()}catch(err:any){console.error(err);alert('Não foi possível salvar o turno. Detalhe: '+(err?.message||JSON.stringify(err)))}}async function toggle(t:Turno){await saveTurno({...t,ativo:!t.ativo});load()}async function excluir(t:Turno){if(!confirm(`Excluir turno ${t.nome}?`))return;await deleteTurno(t.id);load()}return <div className="card adminCard"><div className="sectionHeader"><div><h3>Turnos</h3><p>Defina os turnos que aparecerão no formulário do diário.</p></div><Clock3 size={24}/></div><div className="formGrid adminForm"><label>Nome<input placeholder="Ex.: 1º Turno" value={nome} onChange={e=>setNome(e.target.value)}/></label><label>Início<input type="time" value={inicio} onChange={e=>setInicio(e.target.value)}/></label><label>Fim<input type="time" value={fim} onChange={e=>setFim(e.target.value)}/></label><label>Status<select value={ativo?'ativo':'inativo'} onChange={e=>setAtivo(e.target.value==='ativo')}><option value="ativo">ativo</option><option value="inativo">inativo</option></select></label></div><div className="formActions"><button type="button" className="primary" onClick={salvar}>{edit?'Salvar turno':'Cadastrar turno'}</button>{edit&&<button type="button" className="secondary" onClick={limpar}>Cancelar</button>}</div><div className="smartFilters"><div className="searchBox"><Search size={18}/><input placeholder="Buscar turno..." value={busca} onChange={e=>setBusca(e.target.value)}/></div></div><div className="compactList">{filtrados.map(t=><div className="compactRow" key={t.id}><span>{t.nome}</span><small>{t.inicio} às {t.fim}</small><b className={t.ativo?'txtOk':'txtOff'}>{t.ativo?'ativo':'inativo'}</b><button type="button" className="secondary" onClick={()=>editar(t)}>Editar</button><button type="button" className="secondary" onClick={()=>toggle(t)}>{t.ativo?'Inativar':'Ativar'}</button><button type="button" className="secondary dangerSoft" onClick={()=>excluir(t)}><Trash2 size={16}/> Excluir</button></div>)}</div></div>}
function LogsAdmin(){const[items,setItems]=useState<AuditLog[]>([]),[busca,setBusca]=useState(''),[entidade,setEntidade]=useState('todas');useEffect(()=>{listAudit().then(setItems)},[]);const filtrados=items.filter(l=>`${l.entidade} ${l.acao} ${l.usuario_nome} ${JSON.stringify(l.detalhes||{})}`.toLowerCase().includes(busca.toLowerCase())).filter(l=>entidade==='todas'||l.entidade===entidade);return <div className="card adminCard"><div className="sectionHeader"><div><h3>Logs administrativos</h3><p>Rastreabilidade das alterações feitas no sistema.</p></div><Activity size={24}/></div><div className="smartFilters"><div className="searchBox"><Search size={18}/><input placeholder="Buscar por usuário, ação ou detalhe..." value={busca} onChange={e=>setBusca(e.target.value)}/></div><select value={entidade} onChange={e=>setEntidade(e.target.value)}><option value="todas">Todas as entidades</option><option value="usuarios">Usuários</option><option value="setores">Setores</option><option value="maquinas">Máquinas</option><option value="turnos">Turnos</option><option value="diarios">Diários</option></select></div>{!filtrados.length&&<EmptyState text="Nenhum log encontrado."/>}<div className="logList">{filtrados.map(l=><div className="logRow" key={l.id}><b>{l.acao} • {l.entidade}</b><span>{l.usuario_nome} • {new Date(l.criado_em).toLocaleString('pt-BR')}</span><code>{JSON.stringify(l.detalhes||{})}</code></div>)}</div></div>}
function ConfigAdmin(){return <div className="card adminCard"><div className="sectionHeader"><div><h3>Configurações gerais</h3><p>Parâmetros visuais e operacionais da plataforma.</p></div><SlidersHorizontal size={24}/></div><div className="configGrid"><div className="configTile"><b>Nome do aplicativo</b><span>Diário de Bordo Trevo</span></div><div className="configTile"><b>Áreas principais do dashboard</b><span>Envase 1, Envase 2 e Processo</span></div><div className="configTile"><b>Sincronização</b><span>Offline First com fila local e sincronização Supabase</span></div><div className="configTile"><b>Permissões</b><span>Administrador: acesso total. Usuário: leitura geral e edição apenas dos próprios lançamentos.</span></div></div></div>}
function App(){const[ok,setOk]=useState(!!currentUser());useEffect(()=>{if('serviceWorker'in navigator)navigator.serviceWorker.register('/sw.js')},[]);return ok?<Shell/>:<Login onOk={()=>setOk(true)}/>}createRoot(document.getElementById('root')!).render(<App/>);
